INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (1, 'Kulit pisang', '🍌', 'organik', 'rumah', 'Pakan maggot / kompos', '2–10 minggu', 'Kulit pisang bisa jadi pengkilap sepatu dan pupuk penyubur tanaman!', 1, '2026-07-18 17:13:32', '2026-07-18 17:13:32');
