INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (117, 'Kulit melinjo & petai', '🫛', 'organik', 'rumah', 'Kompos / bahan POC', '2–4 minggu', 'Kulit melinjo bahkan bisa diolah jadi keripik dan abon bernilai jual.', 117, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (118, 'Bangkai hewan kecil', '🐁', 'organik', 'rumah', 'Kubur sedalam ±50 cm, jauh dari sumur — jangan ke sungai', 'beberapa minggu', 'Bangkai yang dibuang ke air adalah sumber penyakit bagi warga di hilir.', 118, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (119, 'Rambut & potongan kuku', '✂️', 'organik', 'rumah', 'Kompos lambat / taburkan di sekitar tanaman', '1–2 tahun', 'Rambut kaya nitrogen dan konon membantu mengusir siput dari tanaman.', 119, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (120, 'Aluminium foil bekas', '🥡', 'anorganik', 'rumah', 'Bersihkan, gulung jadi bola, setor ke pengepul logam', 'ratusan tahun', 'Foil bersih bisa didaur ulang seperti kaleng; yang kotor terpaksa jadi residu.', 120, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (121, 'Ban dalam & karet bekas', '⚫', 'anorganik', 'bengkel', 'Jadi tali timba, alas, atau setor ke pengepul', 'ratusan tahun', 'Karet yang dibakar mengeluarkan asap hitam pekat yang sangat beracun.', 121, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (122, 'Tas & dompet imitasi rusak', '👜', 'anorganik', 'rumah', 'Donasikan bila layak; jika rusak total, buang ke residu', 'puluhan–ratusan tahun', 'Kulit sintetis sebenarnya plastik (PVC/PU) — awet di alam seperti plastik lain.', 122, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (123, 'Kemasan pouch isi ulang', '🧼', 'anorganik', 'rumah', 'Kumpulkan bersih — bahan ecobrick / kerajinan', 'puluhan tahun', 'Pouch berlapis-lapis sulit didaur ulang — paling cocok jadi isi ecobrick.', 123, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (124, 'Korek gas & kaleng gas portable', '🔥', 'b3', 'rumah', 'Pastikan gas benar-benar habis; jangan dibakar atau ditusuk', 'ratusan tahun', 'Sisa gas bertekanan bisa meledak bila terkena panas — bahaya di tumpukan sampah.', 124, '2026-07-18 17:13:37', '2026-07-18 17:13:37');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (125, 'Semir, cat rambut & kutek', '💅', 'b3', 'rumah', 'Habiskan isinya; sisa & kemasannya serahkan ke dropbox B3', 'tidak terurai alami', 'Aseton dan amonia di dalamnya mengiritasi kulit serta mencemari air.', 125, '2026-07-18 17:13:38', '2026-07-18 17:13:38');
INSERT INTO "waste_items" ("id", "nama", "emoji", "kategori", "sumber", "saran", "waktu_urai", "fakta", "urutan", "created_at", "updated_at") VALUES (126, 'Raket nyamuk & senter rusak', '🦟', 'b3', 'rumah', 'Lepas baterainya, serahkan sebagai e-waste — jangan dibongkar sembarangan', 'tidak terurai', 'Raket nyamuk masih menyimpan muatan listrik meski sudah mati — hati-hati saat membongkar.', 126, '2026-07-18 17:13:38', '2026-07-18 17:13:38');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (1, 'Sampah organik paling cocok diolah menjadi apa di Desa Pajaten?', '["Dibakar di pekarangan", "Kompos, POC, atau pakan maggot", "Dibuang ke irigasi", "Ditimbun di kantong plastik"]'::jsonb, 1, 'Sampah organik cepat terurai dan kaya nutrisi, cocok jadi kompos, POC, atau pakan maggot.', true, 1, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (2, 'Ke mana sampah anorganik seperti botol plastik sebaiknya disalurkan?', '["Bank Sampah di Kantor Kepala Desa", "Dibakar bersama daun kering", "Saluran irigasi", "Dipendam di kebun"]'::jsonb, 0, 'Sampah anorganik ditabung ke Bank Sampah agar bernilai, bukan dibakar atau dibuang.', true, 2, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (3, 'Apa keuntungan menabung sampah di Bank Sampah?', '["Tidak ada untungnya", "Sampah ditimbang dan jadi tabungan uang", "Dapat hadiah motor", "Sampah dibuang lebih jauh"]'::jsonb, 1, 'Sampah ditimbang, dicatat, lalu nilainya masuk ke buku tabunganmu.', true, 3, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (4, 'Eceng gondok dari irigasi bisa dimanfaatkan menjadi?', '["Pakan ternak setelah dicacah", "Bahan bakar kompor", "Pengganti pupuk kimia langsung", "Tidak bisa dimanfaatkan"]'::jsonb, 0, 'Eceng gondok dicacah lalu dicampur keong sawah menjadi pakan ternak murah.', true, 4, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (5, 'Mengapa membuang sampah ke irigasi dilarang?', '["Airnya jadi lebih jernih", "Menyumbat aliran dan memicu banjir", "Ikan jadi lebih banyak", "Sampah cepat terurai di air"]'::jsonb, 1, 'Sampah menyumbat aliran air irigasi sehingga berisiko memicu banjir.', true, 5, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (6, 'Tempat sampah untuk sampah organik umumnya berwarna?', '["Merah", "Kuning", "Hijau", "Biru"]'::jsonb, 2, 'Hijau menandakan sampah organik yang mudah terurai; kuning untuk anorganik.', true, 6, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (7, 'Maggot (belatung BSF) diberi makan dari?', '["Sampah plastik", "Sisa makanan & sampah organik", "Kaca dan logam", "Kertas kering"]'::jsonb, 1, 'Maggot memakan sampah organik dan tumbuh jadi pakan ternak bergizi.', true, 7, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (8, 'Apa kepanjangan dari prinsip 3R?', '["Reduce, Reuse, Recycle", "Read, Run, Rest", "Reduce, Repeat, Return", "Reuse, Rinse, Repeat"]'::jsonb, 0, '3R = Reduce (kurangi), Reuse (pakai ulang), Recycle (daur ulang).', true, 8, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (9, 'POC yang dibuat warga berasal dari?', '["Botol plastik dilelehkan", "Fermentasi sampah sayur & kulit buah", "Air irigasi kotor", "Abu pembakaran sampah"]'::jsonb, 1, 'POC (Pupuk Organik Cair) dibuat dari fermentasi sampah organik dengan EM4 atau air cucian beras.', true, 9, '2026-07-14 18:01:47', '2026-07-14 18:01:47');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (10, 'Sampah mana yang biasanya bernilai jual paling tinggi di Bank Sampah?', '["Daun kering", "Kaleng/logam aluminium", "Sisa makanan", "Kulit pisang"]'::jsonb, 1, 'Logam seperti aluminium punya harga jual tinggi dibanding sampah lain.', true, 10, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (11, 'Baterai bekas, lampu, dan obat kadaluarsa termasuk jenis sampah?', '["Organik", "Anorganik biasa", "B3 (Bahan Berbahaya & Beracun)", "Bisa dibakar saja"]'::jsonb, 2, 'Semuanya mengandung zat berbahaya, jadi tergolong B3 dan wajib ditangani khusus.', true, 11, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (12, 'Bagaimana cara benar menangani sampah B3 seperti baterai bekas?', '["Dibuang ke tempat sampah biasa", "Dibakar agar cepat habis", "Dikumpulkan terpisah & diserahkan ke fasilitas khusus", "Dikubur di kebun"]'::jsonb, 2, 'Sampah B3 dikumpulkan terpisah lalu diserahkan ke dropbox B3/pengepul resmi agar tidak mencemari.', true, 12, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (13, 'Bagaimana sistem penyetoran sampah di Bank Sampah Desa Pajaten?', '["Per kelompok dusun, kira-kira seminggu sekali", "Perorangan setiap hari", "Setahun sekali saat panen", "Lewat pos ke kecamatan"]'::jsonb, 0, 'Setoran dikoordinasikan per kelompok dusun (bukan perorangan) sekitar seminggu sekali, dengan target 5 kg plastik per kelompok.', true, 13, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (14, 'Kalau setoran kelompokmu minggu ini baru 3 kg (belum sampai 5 kg), apa yang terjadi?', '["Hangus dan tidak dihitung", "Dicatat dan diakumulasikan ke minggu berikutnya", "Harus bayar denda", "Dikembalikan ke warga"]'::jsonb, 1, 'Setoran yang belum mencapai target tidak hangus — tercatat dan diakumulasikan ke minggu berikutnya.', true, 14, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (15, 'Supaya sampah plastikmu dihargai lebih tinggi di Bank Sampah, sebaiknya?', '["Disetor tercampur apa adanya", "Dibasahi supaya lebih berat", "Dipilah sendiri: botol & gelas dipisah, bersih, tanpa label", "Dibakar sebagian"]'::jsonb, 2, 'Sampah campur dihargai dengan patokan terendah; yang dipilah sendiri, bersih, dan tanpa label dihargai lebih tinggi.', true, 15, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "quiz_questions" ("id", "pertanyaan", "opsi", "jawaban", "penjelasan", "aktif", "urutan", "created_at", "updated_at") VALUES (16, 'Hasil timbangan sampahmu di Bank Sampah dicatat di mana?', '["Hanya diingat petugas", "Buku tabungan fisik dan pencatatan digital berbasis web", "Ditulis di papan pengumuman saja", "Tidak dicatat"]'::jsonb, 1, 'Pencatatan dilakukan ganda: buku tabungan fisik milik warga dan pencatatan digital yang dipegang pihak desa sebagai cadangan.', true, 16, '2026-07-14 18:01:48', '2026-07-14 18:01:48');
INSERT INTO "umkms" ("id", "emoji", "nama", "deskripsi", "tag", "created_at", "updated_at") VALUES (1, '🍘', 'Opak Ketan "Sumber Rasa"', 'Produk khas & unggulan Desa Pajaten. Kerupuk ketan tradisional turun-temurun lebih dari 30 tahun — dari menumbuk ketan, mencetak, menjemur, hingga memanggang di atas bara. Desa Pajaten dikenal sebagai penghasil opak.', 'Unggulan', '2026-07-14 01:32:19', '2026-07-14 01:32:19');
INSERT INTO "umkms" ("id", "emoji", "nama", "deskripsi", "tag", "created_at", "updated_at") VALUES (2, '🌾', 'Pertanian Padi & Sawah', 'Mayoritas warga bertani padi, didukung jaringan irigasi desa.', NULL, '2026-07-14 01:32:20', '2026-07-14 01:32:20');
INSERT INTO "umkms" ("id", "emoji", "nama", "deskripsi", "tag", "created_at", "updated_at") VALUES (3, '🧵', 'Konveksi & Jahit', 'Usaha jahit dan obras rumahan warga.', NULL, '2026-07-14 01:32:20', '2026-07-14 01:32:20');
INSERT INTO "umkms" ("id", "emoji", "nama", "deskripsi", "tag", "created_at", "updated_at") VALUES (4, '🐐', 'Peternakan Warga', 'Budidaya ternak sebagai sumber penghidupan warga.', NULL, '2026-07-14 01:32:20', '2026-07-14 01:32:20');
INSERT INTO "umkms" ("id", "emoji", "nama", "deskripsi", "tag", "created_at", "updated_at") VALUES (5, '🍢', 'Olahan Pangan PKK / PEKKA', 'Produk olahan ibu-ibu PKK & Perempuan Kepala Keluarga, didorong lewat program P2WKSS 2026.', NULL, '2026-07-14 01:32:20', '2026-07-14 01:32:20');
