INSERT INTO "schedules" ("id", "minggu", "tanggal", "jam", "periode", "judul", "tempat", "deskripsi", "hasil", "foto", "foto_2", "status", "ikon", "urutan", "created_at", "updated_at") VALUES (1, 1, '2026-07-08', '08:00', NULL, 'Pelepasan KKN di Universitas Buana Perjuangan Karawang', 'Kampus UBP Karawang', 'Pelepasan resmi peserta KKN oleh pihak universitas.', 'Peserta KKN resmi dilepas oleh Universitas.', 'jadwal/01KXT0WHDC164JN80QVWNFRN6X.jpg', NULL, 'done', '🎓', 1, '2026-07-17 12:11:46', '2026-07-18 16:58:06');
INSERT INTO "schedules" ("id", "minggu", "tanggal", "jam", "periode", "judul", "tempat", "deskripsi", "hasil", "foto", "foto_2", "status", "ikon", "urutan", "created_at", "updated_at") VALUES (2, 1, '2026-07-08', '08:00', NULL, 'Pembukaan KKN di Desa Pajaten', 'Kantor Desa Pajaten', 'Penerimaan peserta KKN oleh Pemerintah Desa Pajaten.', 'Peserta KKN diterima oleh Pemerintah Desa Pajaten. Terjalin koordinasi awal dengan pihak desa mengenai pelaksanaan KKN.', 'jadwal/W5ENBLI5QgFbYjmHRK35CYo5.webp', NULL, 'done', '🎤', 2, '2026-07-17 12:11:46', '2026-07-18 08:23:42');
INSERT INTO "schedules" ("id", "minggu", "tanggal", "jam", "periode", "judul", "tempat", "deskripsi", "hasil", "foto", "foto_2", "status", "ikon", "urutan", "created_at", "updated_at") VALUES (3, 1, '2026-07-09', '10:00', NULL, 'Berkunjung ke kediaman Ketua RT', 'Rumah Ketua RT', 'Silaturahmi sekaligus permohonan izin pelaksanaan program kerja.', 'Terjalin silaturahmi dan komunikasi dengan Pak RT. Diperoleh izin dan dukungan untuk pelaksanaan program kerja KKN di wilayah setempat.', 'jadwal/QrN1mo20zToQ7WZ186kTBmMk.webp', NULL, 'done', '🤝', 3, '2026-07-17 12:11:46', '2026-07-18 08:28:08');
INSERT INTO "schedules" ("id", "minggu", "tanggal", "jam", "periode", "judul", "tempat", "deskripsi", "hasil", "foto", "foto_2", "status", "ikon", "urutan", "created_at", "updated_at") VALUES (4, 1, '2026-07-09', '17:00', NULL, 'Berkunjung ke kediaman Wakil Ketua RT & Kepala Dusun', 'Rumah Wakil Ketua RT & Kepala Dusun', 'Lanjutan perizinan wilayah kepada Wakil Ketua RT dan Kepala Dusun.', 'Terjalin silaturahmi dengan Wakil Ketua RT serta Kepala Dusun, disertai dukungan untuk pelaksanaan program kerja KKN.', 'jadwal/DMaL1oOvoxKjTCzbVvMh6lTE.webp', NULL, 'done', '🤝', 4, '2026-07-17 12:11:46', '2026-07-18 08:29:48');
INSERT INTO "schedules" ("id", "minggu", "tanggal", "jam", "periode", "judul", "tempat", "deskripsi", "hasil", "foto", "foto_2", "status", "ikon", "urutan", "created_at", "updated_at") VALUES (5, 1, '2026-07-10', '07:00', NULL, 'Jumsih (Jum''at Bersih)', 'Sekitar Kantor Desa Pajaten', 'Kerja bakti kebersihan bersama warga di lingkungan Kantor Desa.', 'Lingkungan sekitar Kantor Desa menjadi lebih bersih serta meningkatkan semangat gotong royong dan kepedulian terhadap kebersihan lingkungan.', 'jadwal/jumsih-jumat-bersih.webp', NULL, 'done', '🧹', 5, '2026-07-17 12:11:46', '2026-07-18 18:00:56');
